fn render_tui_buffer(&self, right_content: &str, prompt: &str, prompt_cursor: usize) -> Buffer {
    let backend = TestBackend::new(self.width, self.height);
    let mut terminal = Terminal::new(backend).expect("test backend is valid");
    terminal
        .draw(|frame| {
            let area = frame.size();
            let body_height = area.height.saturating_sub(1);
            let body = Rect::new(area.x, area.y, area.width, body_height);
            let bottom = Rect::new(area.x, body_height, area.width, 1);
            let layout = self.layout();
            let panes = if layout.left_width > 0 {
                Layout::default()
                    .direction(Direction::Horizontal)
                    .constraints([
                        Constraint::Length(layout.left_width),
                        Constraint::Length(layout.right_width),
                    ])
                    .split(body)
            } else {
                vec![body]
            };

            if layout.left_width > 0 {
                frame.render_widget(self.left_widget(), panes[0]);
                frame.render_widget(self.right_widget(right_content), panes[1]);
            } else {
                frame.render_widget(self.right_widget(right_content), panes[0]);
            }
            frame.render_widget(
                Paragraph::new(self.bottom_line(prompt, prompt_cursor)),
                bottom,
            );
        })
        .expect("test backend draw succeeds");
    terminal.backend().buffer().clone()
}

fn left_widget(&self) -> List<'static> {
    let inner_width = usize::from(self.layout().left_width.saturating_sub(2).max(1));
    let items = self
        .left_display_lines(inner_width)
        .into_iter()
        .enumerate()
        .map(|(row, line)| {
            let item = ListItem::new(Spans::from(self.styled_spans_for_line(
                PaneFocus::Left,
                row,
                &line.text,
            )));
            if line.ready {
                item.style(Style::default().add_modifier(Modifier::REVERSED))
            } else {
                item
            }
        })
        .collect::<Vec<_>>();
    List::new(items).block(Block::default().title("work-leaf").borders(Borders::ALL))
}

fn right_widget(&self, right_content: &str) -> Paragraph<'static> {
    let title = match self.windows[self.active_window].surface {
        UiSurface::WorkLeafCommand => "command",
        UiSurface::AgentChat => "chat",
    };
    let lines = right_content
        .split('\n')
        .enumerate()
        .map(|(row, line)| Spans::from(self.styled_spans_for_line(PaneFocus::Right, row, line)))
        .collect::<Vec<_>>();
    Paragraph::new(lines)
        .block(Block::default().title(title).borders(Borders::ALL))
        .wrap(Wrap { trim: false })
}

fn bottom_line(&self, prompt: &str, prompt_cursor: usize) -> String {
    if self.mode == UiMode::Prompt {
        self.prompt_view(prompt, prompt_cursor).line
    } else {
        self.render_status_line()
    }
}

fn cursor_sequence(&self, right_content: &str, prompt: &str) -> String {
    self.cursor_sequence_with_cursors(right_content, prompt, prompt.len(), None)
}

fn cursor_sequence_with_cursors(
    &self,
    right_content: &str,
    prompt: &str,
    prompt_cursor: usize,
    right_cursor_column: Option<usize>,
) -> String {
    let (row, column) = if self.mode == UiMode::Prompt {
        (
            self.height,
            self.prompt_view(prompt, prompt_cursor).cursor_column,
        )
    } else if let Some(position) = self.visual_cursor_screen_position() {
        position
    } else {
        match self.focus {
            PaneFocus::Left => (self.control_cursor_row(), 2),
            PaneFocus::Right => {
                self.right_cursor_position_with_cursor(right_content, right_cursor_column)
            }
        }
    };
    let row = row.clamp(1, self.height.max(1));
    let column = column.clamp(1, self.width.max(1));
    format!("\u{1b}[{row};{column}H")
}

fn prompt_view(&self, prompt: &str, prompt_cursor: usize) -> PromptView {
    let width = usize::from(self.width.max(1));
    let input_width = width.saturating_sub(1);
    let max_cursor_offset = width.saturating_sub(2);
    let cursor_chars = cursor_char_count(prompt, prompt_cursor);
    let start = cursor_chars.saturating_sub(max_cursor_offset);
    let visible_prompt = prompt
        .chars()
        .skip(start)
        .take(input_width)
        .collect::<String>();
    let cursor_offset = cursor_chars.saturating_sub(start).min(max_cursor_offset);
    let cursor_column = if self.width <= 1 {
        1
    } else {
        cursor_offset.saturating_add(2).min(width) as u16
    };
    PromptView {
        line: format!(":{visible_prompt}"),
        cursor_column,
    }
}

fn bell_prefix(&self) -> &'static str {
    if self.pending_bell.replace(false) {
        "\u{7}"
    } else {
        ""
    }
}

fn clipboard_prefix(&self) -> String {
    self.pending_clipboard_text
        .replace(None)
        .map(|text| osc52_clipboard_sequence(&text))
        .unwrap_or_default()
}

fn handle_pending_key(&mut self, pending: PendingKey, key: UiKey) -> Vec<UiAction> {
    match (pending, key) {
        (PendingKey::CtrlW, UiKey::Char('h')) if self.mode == UiMode::Command => {
            if self.left_visible {
                self.focus = PaneFocus::Left;
            }
            Vec::new()
        }
        (PendingKey::CtrlW, UiKey::Char('k')) if self.mode == UiMode::Command => {
            if self.left_visible {
                self.focus = PaneFocus::Left;
            }
            Vec::new()
        }
        (PendingKey::CtrlW, UiKey::Char('l')) if self.mode == UiMode::Command => {
            self.focus = PaneFocus::Right;
            self.mode = UiMode::Command;
            Vec::new()
        }
        (PendingKey::CtrlW, UiKey::Char('j')) if self.mode == UiMode::Command => {
            self.focus = PaneFocus::Right;
            self.mode = UiMode::Command;
            Vec::new()
        }
        (PendingKey::G, UiKey::Char('t')) if self.mode == UiMode::Command => {
            self.next_window();
            Vec::new()
        }
        (PendingKey::G, UiKey::Char('T')) if self.mode == UiMode::Command => {
            self.previous_window();
            Vec::new()
        }
        _ => Vec::new(),
    }
}

fn handle_visual_key(&mut self, key: UiKey) -> Vec<UiAction> {
    match key {
        UiKey::Esc => self.clear_visual_selection(),
        UiKey::Char('h') | UiKey::Left => self.move_visual_cursor(0, -1),
        UiKey::Char('j') | UiKey::Down => self.move_visual_cursor(1, 0),
        UiKey::Char('k') | UiKey::Up => self.move_visual_cursor(-1, 0),
        UiKey::Char('l') | UiKey::Right => self.move_visual_cursor(0, 1),
        UiKey::Char('v') => self.toggle_visual_mode(VisualMode::Character),
        UiKey::Char('V') => self.toggle_visual_mode(VisualMode::Line),
        UiKey::Char('\u{16}') => self.toggle_visual_mode(VisualMode::Block),
        UiKey::Char('y') => self.yank_visual_selection(false),
        UiKey::Char('Y') => self.yank_visual_selection(true),
        _ => {}
    }
    Vec::new()
}

fn start_visual_selection(&mut self, mode: VisualMode) {
    let pane = self.focused_visual_pane();
    let position = self.clamp_text_position(pane, self.focused_visual_position(pane));
    self.visual_selection = Some(VisualSelection {
        pane,
        mode,
        anchor: position,
        cursor: position,
    });
    self.pending = None;
    self.mode = UiMode::Command;
}

fn toggle_visual_mode(&mut self, mode: VisualMode) {
    let Some(mut selection) = self.visual_selection else {
        self.start_visual_selection(mode);
        return;
    };
    if selection.mode == mode {
        self.clear_visual_selection();
    } else {
        selection.mode = mode;
        self.visual_selection = Some(selection);
    }
}

fn move_visual_cursor(&mut self, row_delta: isize, column_delta: isize) {
    let Some(mut selection) = self.visual_selection else {
        return;
    };
    let lines = self.pane_text_lines(selection.pane);
    let max_row = lines.len().saturating_sub(1);
    let next_row = apply_delta(selection.cursor.row, row_delta).min(max_row);
    let line_len = lines
        .get(next_row)
        .map(|line| line.chars().count())
        .unwrap_or_default();
    let max_column = line_len.saturating_sub(1);
    let next_column = apply_delta(selection.cursor.column, column_delta).min(max_column);
    selection.cursor = TextPosition {
        row: next_row,
        column: next_column,
    };
    self.visual_selection = Some(selection);
}

fn yank_visual_selection(&mut self, force_linewise: bool) {
    let Some(selection) = self.visual_selection else {
        return;
    };
    let text = self.selected_text(selection, force_linewise);
    let char_count = self.store_yank(text);
    self.clear_visual_selection();
    self.show_status_notice(
        format!("yanked {char_count} chars"),
        Duration::from_secs(STATUS_NOTICE_SECONDS),
    );
}

fn yank_focused_line(&mut self) {
    let pane = self.focused_visual_pane();
    let lines = self.pane_text_lines(pane);
    let position = self.clamp_text_position(pane, self.focused_visual_position(pane));
    let text = lines.get(position.row).cloned().unwrap_or_default();
    let char_count = self.store_yank(text);
    self.show_status_notice(
        format!("yanked {char_count} chars"),
        Duration::from_secs(STATUS_NOTICE_SECONDS),
    );
}

fn store_yank(&mut self, text: String) -> usize {
    let char_count = text.chars().count();
    self.pending_clipboard_text.replace(Some(text.clone()));
    self.yank_register = Some(text);
    char_count
}

fn selected_text(&self, selection: VisualSelection, force_linewise: bool) -> String {
    let lines = self.pane_text_lines(selection.pane);
    if lines.is_empty() {
        return String::new();
    }

    if force_linewise || selection.mode == VisualMode::Line {
        let (start, end) = ordered_rows(selection.anchor.row, selection.cursor.row);
        return lines[start..=end.min(lines.len() - 1)].join("\n");
    }

    match selection.mode {
        VisualMode::Character => self.character_selection_text(selection, &lines),
        VisualMode::Block => self.block_selection_text(selection, &lines),
        VisualMode::Line => unreachable!("line selections returned before mode dispatch"),
    }
}

fn character_selection_text(&self, selection: VisualSelection, lines: &[String]) -> String {
    let (start, end) = ordered_positions(selection.anchor, selection.cursor);
    let end_row = end.row.min(lines.len().saturating_sub(1));
    let mut selected = Vec::new();
    for (row, line) in lines
        .iter()
        .enumerate()
        .take(end_row.saturating_add(1))
        .skip(start.row)
    {
        let line_len = line.chars().count();
        if line_len == 0 {
            selected.push(String::new());
            continue;
        }
        let start_column = if row == start.row {
            start.column.min(line_len.saturating_sub(1))
        } else {
            0
        };
        let end_column = if row == end.row {
            end.column.min(line_len.saturating_sub(1))
        } else {
            line_len.saturating_sub(1)
        };
        selected.push(char_slice(line, start_column, end_column.saturating_add(1)));
    }
    selected.join("\n")
}

fn block_selection_text(&self, selection: VisualSelection, lines: &[String]) -> String {
    let (start_row, end_row) = ordered_rows(selection.anchor.row, selection.cursor.row);
    let (start_column, end_column) =
        ordered_rows(selection.anchor.column, selection.cursor.column);
    let end_row = end_row.min(lines.len().saturating_sub(1));
    let mut selected = Vec::new();
    for line in &lines[start_row..=end_row] {
        let line_len = line.chars().count();
        if start_column >= line_len {
            selected.push(String::new());
        } else {
            selected.push(char_slice(
                line,
                start_column,
                end_column.saturating_add(1).min(line_len),
            ));
        }
    }
    selected.join("\n")

    selected.join("\n")
}

fn focused_visual_pane(&self) -> PaneFocus {
    if self.focus == PaneFocus::Left && !self.left_visible {
        PaneFocus::Right
    } else {
        self.focus
    }
}

fn focused_visual_position(&self, pane: PaneFocus) -> TextPosition {
    match pane {
        PaneFocus::Left => TextPosition {
            row: self.left_display_row_for_control_selection(),
            column: 0,
        },
        PaneFocus::Right => TextPosition { row: 0, column: 0 },
    }
}

fn clamp_text_position(&self, pane: PaneFocus, position: TextPosition) -> TextPosition {
    let lines = self.pane_text_lines(pane);
    let max_row = lines.len().saturating_sub(1);
    let row = position.row.min(max_row);
    let line_len = lines
        .get(row)
        .map(|line| line.chars().count())
        .unwrap_or_default();
    TextPosition {
        row,
        column: position.column.min(line_len.saturating_sub(1)),
    }
}

fn pane_text_lines(&self, pane: PaneFocus) -> Vec<String> {
    match pane {
        PaneFocus::Left => {
            let inner_width = usize::from(self.layout().left_width.saturating_sub(2).max(1));
            self.left_display_lines(inner_width)
                .into_iter()
                .map(|line| line.text)
                .collect()
        }
        PaneFocus::Right => self
            .cached_right_content
            .borrow()
            .split('\n')
            .map(ToString::to_string)
            .collect(),
    }
}

fn left_display_lines(&self, inner_width: usize) -> Vec<DisplayLine> {
    let mut lines = vec![DisplayLine {
        text: if self.control_selected == 0 {
            "> work-leaf  command".to_string()
        } else {
            "  work-leaf  command".to_string()
        },
        ready: false,
    }];
    for (visible_position, agent_index) in self.visible_agent_indices().iter().enumerate() {
        let agent = &self.agents[*agent_index];
        let selected = self.control_selected == visible_position + 1;
        lines.push(DisplayLine {
            text: compact_agent_row(agent, selected, inner_width),
            ready: agent.ready,
        });
        if !agent.modified_files.is_empty() {
            lines.push(DisplayLine {
                text: format!(
                    "    files: {}",
                    agent
                        .modified_files
                        .iter()
                        .map(|path| path.display().to_string())
                        .collect::<Vec<_>>()
                        .join(", ")
                ),
                ready: false,
            });
        }
        for (label, agents) in [
            ("conflicts", &agent.conflicting_agents),
            ("depends-on", &agent.depends_on),
            ("depended-on-by", &agent.depended_on_by),
        ] {
            if !agents.is_empty() {
                lines.push(DisplayLine {
                    text: format!(
                        "    {label}: {}",
                        agents
                            .iter()
                            .map(AgentId::as_str)
                            .collect::<Vec<_>>()
                            .join(", ")
                    ),
                    ready: false,
                });
            }
        }
    }
    lines
}

fn left_display_row_for_control_selection(&self) -> usize {
    if self.control_selected == 0 {
        return 0;
    }

    let mut row = 1;
    for (visible_position, agent_index) in self.visible_agent_indices().iter().enumerate() {
        if self.control_selected == visible_position + 1 {
            return row;
        }

        let agent = &self.agents[*agent_index];
        row += 1;
        if !agent.modified_files.is_empty() {
            row += 1;
        }
        for linked_agents in [
            &agent.conflicting_agents,
            &agent.depends_on,
            &agent.depended_on_by,
        ] {
            if !linked_agents.is_empty() {
                row += 1;
            }
        }
    }

    0
}

fn styled_spans_for_line(&self, pane: PaneFocus, row: usize, line: &str) -> Vec<Span<'static>> {
    let Some(range) = self.selected_range_for_line(pane, row, line.chars().count()) else {
        return vec![Span::raw(line.to_string())];
    };

    let mut spans = Vec::new();
    if range.start > 0 {
        spans.push(Span::raw(char_slice(line, 0, range.start)));
    }
    spans.push(Span::styled(
        char_slice(line, range.start, range.end),
        Style::default().add_modifier(Modifier::REVERSED),
    ));
    let line_len = line.chars().count();
    if range.end < line_len {
        spans.push(Span::raw(char_slice(line, range.end, line_len)));
    }
    spans
}

fn selected_range_for_line(
    &self,
    pane: PaneFocus,
    row: usize,
    line_len: usize,
) -> Option<std::ops::Range<usize>> {
    if line_len == 0 {
        return None;
    }
    let selection = self.visual_selection?;
    if selection.pane != pane {
        return None;
    }

    match selection.mode {
        VisualMode::Character => {
            let (start, end) = ordered_positions(selection.anchor, selection.cursor);
            if row < start.row || row > end.row {
                return None;
            }
            let start_column = if row == start.row {
                start.column.min(line_len.saturating_sub(1))
            } else {
                0
            };
            let end_column = if row == end.row {
                end.column.min(line_len.saturating_sub(1))
            } else {
                line_len.saturating_sub(1)
            };
            Some(start_column..end_column.saturating_add(1).min(line_len))
        }
        VisualMode::Line => {
            let (start, end) = ordered_rows(selection.anchor.row, selection.cursor.row);
            (start..=end).contains(&row).then_some(0..line_len)
        }
        VisualMode::Block => {
            let (start_row, end_row) = ordered_rows(selection.anchor.row, selection.cursor.row);
            if row < start_row || row > end_row {
                return None;
            }
            let (start_column, end_column) =
                ordered_rows(selection.anchor.column, selection.cursor.column);
            if start_column >= line_len {
                None
            } else {
                Some(start_column..end_column.saturating_add(1).min(line_len))
            }
        }
    }
}

fn visual_cursor_screen_position(&self) -> Option<(u16, u16)> {
    let selection = self.visual_selection?;
    let layout = self.layout();
    let row = 2_u16.saturating_add(selection.cursor.row.min(usize::from(u16::MAX)) as u16);
    let column_offset = selection.cursor.column.min(usize::from(u16::MAX)) as u16;
    let column = match selection.pane {
        PaneFocus::Left => 2_u16.saturating_add(column_offset),
        PaneFocus::Right => layout
            .left_width
            .saturating_add(2)
            .saturating_add(column_offset),
    };
    Some((row, column))
}

fn clear_visual_selection(&mut self) {
    self.visual_selection = None;
}

fn command_mode_text_key_control_status(&self, key: UiKey) -> Option<bool> {
    if self.mode != UiMode::Command || self.pending.is_some() || self.visual_selection.is_some()
    {
        return None;
    }
    let UiKey::Char(ch) = key else {
        return None;
    };
    (ch.is_ascii_alphanumeric() || ch == ' ').then(|| self.is_command_control_char(ch))
}

fn is_command_control_char(&self, ch: char) -> bool {
    matches!(
        ch,
        'i' | ':' | ',' | 's' | 't' | 'f' | 'g' | 'v' | 'V' | 'y' | 'Y'
    ) || (self.focus == PaneFocus::Left && matches!(ch, 'j' | 'k' | 'l' | 'x'))
}

fn update_command_mode_typing_notice(&mut self, command_mode_text_key_control: Option<bool>) {
    if let Some(command_mode_text_key_control) = command_mode_text_key_control
        && self.mode == UiMode::Command
        && self.pending.is_none()
    {
        self.command_mode_typing_count = self.command_mode_typing_count.saturating_add(1);
        self.command_mode_typing_controls_only &= command_mode_text_key_control;
        if self.command_mode_typing_count >= COMMAND_MODE_TYPING_NOTICE_THRESHOLD {
            if !self.command_mode_typing_controls_only {
                self.show_status_notice(
                    COMMAND_MODE_TYPING_NOTICE,
                    Duration::from_secs(STATUS_NOTICE_SECONDS),
                );
            }
            self.command_mode_typing_count = 0;
            self.command_mode_typing_controls_only = true;
        }
    } else {
        self.command_mode_typing_count = 0;
        self.command_mode_typing_controls_only = true;
    }
}

fn show_status_notice(&mut self, message: impl Into<String>, duration: Duration) {
    self.status_notice = Some(StatusNotice {
        message: message.into(),
        expires_at: Instant::now() + duration,
    });
}

fn active_status_notice(&self) -> Option<&str> {
    self.status_notice
        .as_ref()
        .filter(|notice| Instant::now() < notice.expires_at)
        .map(|notice| notice.message.as_str())
}

fn status_notice_expired(&self) -> bool {
    self.status_notice
        .as_ref()
        .is_some_and(|notice| Instant::now() >= notice.expires_at)
}

fn open_selected_same_pane(&mut self) -> Vec<UiAction> {
    let Some(agent_id) = self.action_agent_id() else {
        return Vec::new();
    };
    self.split_chats.push(agent_id.clone());
    vec![UiAction::OpenChatSamePane(agent_id)]
}

fn open_selected_new_window(&mut self) -> Vec<UiAction> {
    let Some(agent_id) = self.action_agent_id() else {
        return Vec::new();
    };
    self.windows.push(UiWindow::chat(agent_id.clone()));
    self.active_window = self.windows.len() - 1;
    vec![UiAction::OpenChatNewWindow(agent_id)]
}

fn fork_selected_agent(&self) -> Vec<UiAction> {
    self.action_agent_id()
        .map(UiAction::ForkAgent)
        .into_iter()
        .collect()
}

fn open_control_selection(&mut self) {
    if self.control_selected == 0 {
        self.select_command_interface();
        self.focus = PaneFocus::Right;
        return;
    }
    if let Some(agent_id) = self.control_selected_agent_id() {
        let _ = self.select_agent(&agent_id);
        self.focus = PaneFocus::Right;
    }
}

fn select_control_row_surface(&mut self) {
    if self.control_selected == 0 {
        self.select_command_interface();
        self.focus = PaneFocus::Left;
        return;
    }
    if let Some(agent_id) = self.control_selected_agent_id() {
        let _ = self.select_agent(&agent_id);
        self.focus = PaneFocus::Left;
    }
}

fn handle_mouse_click(&mut self, column: u16, row: u16) -> Vec<UiAction> {
    if column == 0 || row == 0 {
        return Vec::new();
    }

    let left_width = self.layout().left_width;

    if self.left_visible && column <= left_width {
        self.mode = UiMode::Command;
        self.focus = PaneFocus::Left;
        let Some(target) = self.left_pane_click_target(row) else {
            return Vec::new();
        };
        match target {
            LeftPaneClickTarget::Command => {
                self.select_command_interface();
                self.focus = PaneFocus::Right;
            }
            LeftPaneClickTarget::Agent(agent_id) => {
                let _ = self.activate_agent_chat(&agent_id);
            }
        }
    } else {
        self.focus = PaneFocus::Right;
        self.mode = if self.selected_agent.is_some()
            && self.windows[self.active_window].surface == UiSurface::AgentChat
        {
            UiMode::Insert
        } else {
            UiMode::Command
        };
    }

    Vec::new()
}

fn handle_mouse_scroll(&mut self, column: u16, row: u16, up: bool) {
    if column == 0 || row == 0 || row >= self.height {
        return;
    }

    let left_width = self.layout().left_width;
    if self.left_visible && column <= left_width {
        return;
    }

    if up {
        self.scroll_right_pane_up();
    } else {
        self.scroll_right_pane_down();
    }
}

fn hide_control_selection(&mut self) {
    if self.control_selected == 0 {
        return;
    }
    let Some(agent_index) = self.control_selected_agent_index() else {
        return;
    };
    let hidden_agent = self.agents[agent_index].id.clone();
    self.agents[agent_index].hidden = true;
    let hidden_was_selected = self
        .selected_agent
        .as_ref()

