+    assert!(app.ui().render_left_pane().contains("user-1  working"));
+    assert!(app.ui().render_left_pane().contains("READY"));
+
+    app.handle_bytes(b"yes\n");
+
+    assert!(!app.ui().render_left_pane().contains("user-1  working"));
+    assert!(
+        !backend
+            .sends()
+            .iter()
+            .any(|(_, prompt)| prompt.trim() == "yes"),
